    60	                    .settings(settings(IndexVersion.current()).put(IndexMetadata.SETTING_PRIORITY, priorityFirst))
    61	                    .numberOfShards(2)
    62	                    .numberOfReplicas(1)
    63	            )
    64	            .put(
    65	                IndexMetadata.builder("second")
    66	                    .settings(settings(IndexVersion.current()).put(IndexMetadata.SETTING_PRIORITY, prioritySecond))
    67	                    .numberOfShards(2)
