package org.elasticsearch.cluster.routing.allocation.allocator;

import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;
import org.elasticsearch.cluster.metadata.IndexMetadata;
import org.elasticsearch.cluster.routing.RoutingNode;
import org.elasticsearch.cluster.routing.RoutingNodes;
import org.elasticsearch.cluster.routing.ShardRouting;
import org.elasticsearch.cluster.routing.allocation.AllocateUnassignedDecision;
import org.elasticsearch.cluster.routing.allocation.MoveDecision;
import org.elasticsearch.cluster.routing.allocation.RoutingAllocation;
import org.elasticsearch.cluster.routing.allocation.ShardAllocationDecision;
import org.elasticsearch.cluster.routing.allocation.decider.AllocationDecider;
import org.elasticsearch.cluster.routing.allocation.decider.Decision;
import org.elasticsearch.common.settings.ClusterSettings;
import org.elasticsearch.common.settings.Setting;
import org.elasticsearch.common.settings.Setting.Property;
import org.elasticsearch.injection.guice.Inject;

import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import java.util.TreeMap;

/**
 * A {@link ShardsAllocator} that enforces index-level allocation priority before delegating
 * weight-based placement to an underlying {@link ShardsAllocator} (typically
 * {@link BalancedShardsAllocator}).
 *
 * <p>Unassigned shards are grouped by their index's
 * {@link #INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING} value and presented to the delegate
 * allocator in descending priority order. This ensures that when node capacity or concurrent
 * recovery slots are limited, higher-priority index shards are placed before lower-priority ones.
 *
 * <p>After priority-ordered initial placement, the standard move and balance passes run
 * without priority filtering to preserve long-term cluster balance.
 *
 * <p>Node-level priority constraints are enforced by the companion
 * {@link PriorityAllocationDecider}, which gates placements based on the
 * {@code node.attr.allocation.priority} node attribute.
 *
 * @see PriorityAllocationDecider
 */
public class PriorityShardsAllocator implements ShardsAllocator {

    private static final Logger logger = LogManager.getLogger(PriorityShardsAllocator.class);

    /**
     * Index-scoped setting that controls the allocation priority tier for an index.
     *
     * <p>Valid range: 1 (lowest / default) to 10 (highest). Higher values cause the index's
     * shards to be allocated before lower-valued indices when node capacity is constrained.
     * This setting is dynamic and can be changed via the Index Settings API without a restart.
     *
     * <p>This setting is distinct from {@link IndexMetadata#INDEX_PRIORITY_SETTING}
     * ({@code index.priority}), which controls recovery ordering. The two settings are
     * orthogonal and may be configured independently.
     */
    public static final Setting<Integer> INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING = Setting.intSetting(
        "index.routing.allocation.priority",
        1,   // default: lowest priority tier
        1,   // minimum
        10,  // maximum
        Property.Dynamic,
        Property.IndexScope
    );

    private final ShardsAllocator delegate;

    /**
     * Constructs a {@code PriorityShardsAllocator} wrapping the given delegate allocator.
     *
     * @param delegate       the underlying allocator that performs weight-based placement
     *                       (typically {@link BalancedShardsAllocator})
     * @param clusterSettings cluster settings, reserved for future cluster-level priority
     *                        configuration
     */
    @Inject
    public PriorityShardsAllocator(ShardsAllocator delegate, ClusterSettings clusterSettings) {
        this.delegate = delegate;
    }

    /**
     * Allocates shards to nodes using a two-phase strategy:
     *
     * <ol>
     *   <li><b>Priority-ordered unassigned allocation:</b> Unassigned shards are grouped by
     *       their index's {@link #INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING} and presented to
     *       the delegate allocator from highest to lowest priority. This ensures throttle slots
     *       and available node capacity are consumed by high-priority shards first.</li>
     *   <li><b>Move and balance pass:</b> After all priority groups have been processed, the
     *       delegate's move and balance logic runs on the full routing table without priority
     *       filtering, preserving long-term cluster balance.</li>
     * </ol>
     *
     * @param allocation the current routing allocation state, mutated in place
     */
    @Override
    public void allocate(RoutingAllocation allocation) {
        assert allocation.ignoreDisable() == false;

        if (allocation.routingNodes().size() == 0) {
            // No data nodes: delegate handles the no-node failure path.
            delegate.allocate(allocation);
            return;
        }

        allocateUnassignedByPriority(allocation);

        // Move and balance passes are priority-agnostic: long-term balance matters more
        // than priority isolation during steady-state operation.
        delegate.allocate(allocation);
    }

    /**
     * Returns the allocation decision for a single shard, delegating entirely to the underlying
     * allocator. Priority ordering is a queue-level concern and does not alter per-node decision
     * logic, so the explain API path is unaffected.
     *
     * @param shard      the shard whose allocation decision is requested
     * @param allocation the current routing allocation state
     * @return a {@link ShardAllocationDecision} describing where the shard should be placed
     */
    @Override
    public ShardAllocationDecision decideShardAllocation(ShardRouting shard, RoutingAllocation allocation) {
        return delegate.decideShardAllocation(shard, allocation);
    }

    /**
     * Groups all unassigned shards by their index's allocation priority and presents each group
     * to the delegate allocator in descending priority order (highest first).
     *
     * <p>Shards that the delegate cannot place in a given pass remain in the unassigned queue
     * and are retried in subsequent reroute cycles.
     *
     * @param allocation the current routing allocation state
     */
    private void allocateUnassignedByPriority(RoutingAllocation allocation) {
        // TreeMap with reversed order so iteration goes from priority 10 down to 1.
        Map<Integer, List<ShardRouting>> shardsByPriority = groupUnassignedShardsByPriority(allocation);

        if (shardsByPriority.isEmpty()) {
            logger.trace("no unassigned shards to allocate");
            return;
        }

        logger.debug("allocating unassigned shards across {} priority tiers", shardsByPriority.size());

        for (Map.Entry<Integer, List<ShardRouting>> entry : shardsByPriority.entrySet()) {
            int priority = entry.getKey();
            List<ShardRouting> tierShards = entry.getValue();
            logger.debug("allocating {} unassigned shard(s) at priority tier {}", tierShards.size(), priority);

            /*
             * TODO: Inject only this tier's shards into the unassigned queue and invoke
             *       delegate.allocateUnassigned(allocation). The BalancedShardsAllocator's
             *       Balancer.allocateUnassigned() iterates RoutingNodes.UnassignedShards,
             *       so the injection mechanism must temporarily replace or filter that
             *       iterator. One approach is a PriorityFilteredRoutingAllocation wrapper
             *       that overrides routingNodes().unassigned() to expose only the current
             *       tier's shards. See design_doc.md §4.2 for the full algorithm.
             */
            allocateTier(allocation, tierShards, priority);
        }
    }

    /**
     * Collects all unassigned shards from the routing table and groups them by their index's
     * {@link #INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING} value.
     *
     * @param allocation the current routing allocation state
     * @return a {@link TreeMap} keyed by priority (descending), each value being the list of
     *         unassigned shards at that priority tier
     */
    private Map<Integer, List<ShardRouting>> groupUnassignedShardsByPriority(RoutingAllocation allocation) {
        // Reversed comparator: higher priority integers sort first.
        Map<Integer, List<ShardRouting>> result = new TreeMap<>(Comparator.reverseOrder());

        RoutingNodes.UnassignedShards unassigned = allocation.routingNodes().unassigned();
        for (ShardRouting shard : unassigned) {
            IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shard.index());
            int priority = INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING.get(indexMetadata.getSettings());
            result.computeIfAbsent(priority, k -> new ArrayList<>()).add(shard);
        }

        return result;
    }

    /**
     * Allocates a single priority tier's unassigned shards using the delegate allocator.
     *
     * <p>This is a placeholder for the tier-scoped allocation invocation. The full
     * implementation requires a mechanism to expose only {@code tierShards} through the
     * {@link RoutingNodes.UnassignedShards} iterator seen by the delegate.
     *
     * @param allocation the current routing allocation state
     * @param tierShards the unassigned shards belonging to this priority tier
     * @param priority   the priority value of this tier (for logging)
     */
    private void allocateTier(RoutingAllocation allocation, List<ShardRouting> tierShards, int priority) {
        // TODO: Implement tier-scoped allocation. Options:
        //   1. PriorityFilteredRoutingAllocation — wraps RoutingAllocation and overrides
        //      routingNodes().unassigned() to return only tierShards.
        //   2. Direct manipulation of the UnassignedShards queue with save/restore of
        //      non-tier shards (requires RoutingNodes API extension).
        //   3. Invoke BalancedShardsAllocator.Balancer.allocateUnassigned() directly via
        //      a package-private hook (requires moving PriorityShardsAllocator into the
        //      same package or using a friend accessor pattern).
        logger.trace("allocating tier {} ({} shards) — implementation pending", priority, tierShards.size());
    }

    // -------------------------------------------------------------------------
    // Inner class: PriorityAllocationDecider
    // -------------------------------------------------------------------------

    /**
     * An {@link AllocationDecider} that enforces node-level allocation priority constraints.
     *
     * <p>Nodes may be tagged with the {@code node.attr.allocation.priority} attribute to
     * designate them as dedicated hosts for high-priority indices. A node tagged with value
     * {@code N} will only accept shards from indices whose
     * {@link #INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING} is {@code >= N}.
     *
     * <p>Nodes without the attribute are unrestricted and accept shards from any index.
     *
     * <h3>Example</h3>
     * <pre>
     * # elasticsearch.yml — reserve this node for priority-7-and-above indices
     * node.attr.allocation.priority: 7
     * </pre>
     *
     * <pre>
     * # Index settings — mark index as priority 9 (accepted by the node above)
     * PUT /my-critical-index/_settings
     * { "index.routing.allocation.priority": 9 }
     * </pre>
     *
     * <h3>canRemain behavior</h3>
     * If a node's {@code node.attr.allocation.priority} is raised (e.g., via rolling restart),
     * shards from indices whose priority falls below the new threshold receive a {@code NO}
     * from {@link #canRemain}, triggering relocation to nodes that accept them.
     */
    public static class PriorityAllocationDecider extends AllocationDecider {

        /** Decider label used in allocation explain API responses. */
        public static final String NAME = "priority";

        /**
         * Node attribute key that specifies the minimum index allocation priority this node
         * will accept. Absent means the node is unrestricted.
         */
        static final String NODE_ATTR_ALLOCATION_PRIORITY = "allocation.priority";

        /**
         * Returns a {@link Decision} on whether the given shard can be allocated to the given
         * node based on priority constraints.
         *
         * <ul>
         *   <li>If the node has no {@code node.attr.allocation.priority} attribute, returns
         *       {@link Decision#YES} (unrestricted node).</li>
         *   <li>If the index's priority meets or exceeds the node's minimum, returns
         *       {@link Decision#YES}.</li>
         *   <li>Otherwise returns {@link Decision#NO} with an explanation.</li>
         * </ul>
         *
         * @param shardRouting the shard being considered for allocation
         * @param node         the candidate target node
         * @param allocation   the current routing allocation state
         * @return the allocation decision
         */
        @Override
        public Decision canAllocate(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
            return decidePriority(shardRouting, node, allocation);
        }

        /**
         * Returns a {@link Decision} on whether the given shard can remain on the given node.
         * Uses the same priority-matching logic as {@link #canAllocate}.
         *
         * @param indexMetadata metadata for the shard's index
         * @param shardRouting  the shard being evaluated
         * @param node          the node currently hosting the shard
         * @param allocation    the current routing allocation state
         * @return the allocation decision
         */
        @Override
        public Decision canRemain(
            IndexMetadata indexMetadata,
            ShardRouting shardRouting,
            RoutingNode node,
            RoutingAllocation allocation
        ) {
            return decidePriority(shardRouting, node, allocation);
        }

        /**
         * Core priority-matching logic shared by {@link #canAllocate} and {@link #canRemain}.
         *
         * @param shardRouting the shard being evaluated
         * @param node         the candidate or current node
         * @param allocation   the current routing allocation state
         * @return {@link Decision#YES} if the placement is allowed, {@link Decision#NO} otherwise
         */
        private Decision decidePriority(ShardRouting shardRouting, RoutingNode node, RoutingAllocation allocation) {
            String nodeAttrValue = node.node().getAttributes().get(NODE_ATTR_ALLOCATION_PRIORITY);

            if (nodeAttrValue == null) {
                // Node has no priority restriction — accept any index.
                return allocation.decision(
                    Decision.YES,
                    NAME,
                    "node [%s] has no allocation priority restriction",
                    node.nodeId()
                );
            }

            int nodeMinPriority;
            try {
                nodeMinPriority = Integer.parseInt(nodeAttrValue);
            } catch (NumberFormatException e) {
                // Misconfigured attribute — fail open with a warning rather than blocking allocation.
                logger.warn(
                    "node [{}] has non-integer value [{}] for attribute [{}]; ignoring priority constraint",
                    node.nodeId(),
                    nodeAttrValue,
                    NODE_ATTR_ALLOCATION_PRIORITY
                );
                return allocation.decision(
                    Decision.YES,
                    NAME,
                    "node [%s] attribute [%s] value [%s] is not a valid integer; constraint ignored",
                    node.nodeId(),
                    NODE_ATTR_ALLOCATION_PRIORITY,
                    nodeAttrValue
                );
            }

            IndexMetadata indexMetadata = allocation.metadata().getIndexSafe(shardRouting.index());
            int indexPriority = INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING.get(indexMetadata.getSettings());

            if (indexPriority >= nodeMinPriority) {
                logger.trace(
                    "shard [{}] index priority [{}] meets node [{}] minimum priority [{}]",
                    shardRouting.shardId(),
                    indexPriority,
                    node.nodeId(),
                    nodeMinPriority
                );
                return allocation.decision(
                    Decision.YES,
                    NAME,
                    "index priority [%d] meets node [%s] minimum allocation priority [%d]",
                    indexPriority,
                    node.nodeId(),
                    nodeMinPriority
                );
            }

            logger.trace(
                "shard [{}] index priority [{}] below node [{}] minimum priority [{}]; cannot allocate",
                shardRouting.shardId(),
                indexPriority,
                node.nodeId(),
                nodeMinPriority
            );
            return allocation.decision(
                Decision.NO,
                NAME,
                "index priority [%d] is below node [%s] minimum allocation priority [%d]; "
                    + "set [%s] to a value >= %d or remove the node attribute [node.attr.%s]",
                indexPriority,
                node.nodeId(),
                nodeMinPriority,
                INDEX_ROUTING_ALLOCATION_PRIORITY_SETTING.getKey(),
                nodeMinPriority,
                NODE_ATTR_ALLOCATION_PRIORITY
            );
        }
    }
}

